public class CaptureExample {
    public static void main(String[] args) {
        String name = "Java"; // effectively final（再代入なし）
        int count = 3;        // effectively final

        // OK: effectively finalな変数を参照
        Runnable r1 = () -> {
            System.out.println(name + " x " + count);
        };
        r1.run(); // Java x 3

        int num = 10;
        num = 20; // 再代入 → effectively finalではなくなる

        // コンパイルエラー！numはeffectively finalではない
        // Runnable r2 = () -> System.out.println(num);
    }
}

public class CaptureRules {
    int instanceVar = 100; // インスタンス変数
    static int staticVar = 200; // static変数

    void demo() {
        final int a = 1;     // final → OK
        int b = 2;          // effectively final → OK
        int c = 3;
        c = 4;              // 再代入あり → NG

        Runnable r = () -> {
            System.out.println(a);           // OK
            System.out.println(b);           // OK
            // System.out.println(c);        // コンパイルエラー
            System.out.println(instanceVar); // OK（インスタンス変数）
            System.out.println(staticVar);   // OK（static変数）
            instanceVar = 999;               // OK（インスタンス変数は変更可能）
        };
    }
}

public class ShadowingExample {
    public static void main(String[] args) {
        int x = 10;

        // ラムダ式：シャドーイング不可
        // Consumer<Integer> c = (x) -> {};  // コンパイルエラー！
        // xはすでに外側のスコープで宣言されている

        // 匿名クラス：シャドーイングOK（スコープが別）
        Runnable r = new Runnable() {
            @Override
            public void run() {
                int x = 20; // OK（匿名クラスは別スコープ）
                System.out.println(x); // 20
            }
        };
    }
}

// forループの変数キャプチャ
List<Runnable> tasks = new ArrayList<>();
for (int i = 0; i < 3; i++) {
    int num = i; // ループごとに新しい変数（effectively final）
    tasks.add(() -> System.out.println(num)); // OK
    // tasks.add(() -> System.out.println(i)); // コンパイルエラー！iは再代入される
}
tasks.forEach(Runnable::run); // 0, 1, 2

